class Solution:
    def findTheLongestSubstring(self, s: str) -> int:
        vowels = 'aeiou'
        max_len = 0
        count = {v: 0 for v in vowels}
        left = 0
        for right in range(len(s)):
            if s[right] in count:
                count[s[right]] += 1
            while all(val % 2 == 0 for val in count.values()):
                max_len = max(max_len, right - left + 1)
                if s[left] in count:
                    count[s[left]] -= 1
                left += 1
        return max_len
